def has_cycle(graph):
    visited = set()

    def dfs(u, parent):
        visited.add(u)

        for v in graph.get(u, []):
            if v == parent:
                continue
            if v in visited:
                return True
            if dfs(v, u):
                return True
        return False

    for node in graph:
        if node not in visited:
            if dfs(node, None):
                return True
    return False
